export function checkPath(path,what) {
    if (settings.bindingPaths === 'off')
        return;
    queueMicrotask(() => {
                                                                  
        const mode = settings.bindingPaths;
        if (mode === 'off')
            return;
        const found = describePath(registry, path);
        if (found.ok === true)
            return;
        const detail = found.absent
            ? `${what}("${path}") — "${found.absent}" does not exist on "${found.at}", which is already populated. Nothing will ever put it there, so this ${what === 'bind' ? 'binding' : 'observer'} will never fire. Check the spelling.`
            : `${what}("${path}") — the path does not resolve; it stops at "${found.at || '(root)'}". If it is awaiting async data, initialize a stub so the shape is declared; otherwise check the spelling.`;
        if (mode === 'throw')
            throw new MonadicError('binding-path', detail, path);
                                                                             
        if (found.absent)
            console.error(detail);
        else
            console.warn(detail);
    });
}
