function Union(d,...v){const vals=v.flat();return{description:d,check:x=>vals.includes(x),values:vals,__runtimeType:true}};
const __tjs = globalThis.__tjs?.createRuntime?.() ?? {Union};
/* tjs <- settings.ts */

export const Strictness = Union('Strictness', ['off', 'warn', 'throw'])

export const PathCreation = Union('PathCreation', ['off', 'warn', 'monadic', 'throw'])

export const BindingPaths = Union('BindingPaths', ['off', 'warn', 'throw'])

export const settings = {
    debug: false,
    perf: false,
    strictness: 'warn',
    pathCreation: 'warn',
    bindingPaths: 'warn',
};